def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf * (1 + np.sin(i))
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 2, -2):
                for b in range(1, a + 5):
                    val = np.tan((ratio - a) / (b + 0.1)) * np.log1p(ratio * b)
                    priority += val * np.exp(-b / (a + 1))
            priority += np.sinh(ratio - 7) * np.cos(item * 1.7) * 2.2
            for idx in range(1, 5):
                priority += ((ratio / (item + 1)) ** idx) * np.sin(idx * bin_cap)
        elif 5 < ratio <= 8:
            acc = 0
            for p in range(1, int(np.ceil(ratio))+4):
                for q in range(1, p+4):
                    val = np.exp(-(ratio - p) ** 2) * np.cos(ratio * q) / (np.sqrt(p+q))
                    acc += val
            priority = acc * 1.8 + np.tanh(ratio - 5) * 3.4
            if bin_cap < item * 1.2:
                priority += np.exp(-bin_cap/item) * 5
            else:
                priority -= np.log1p(ratio) * 2.1
        elif 2 < ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r**1.3 + 0.5) * np.sin(r * ratio * 1.1)
            penalty = np.log(bin_cap + 1) * 7
            priority = s - penalty + np.tanh(item / (bin_cap + 0.1)) * 2
            for k in range(3):
                priority += np.cos(ratio * (i + k + 1)) * (0.7 / (k+1))
        elif 0.9 <= ratio <= 2:
            total = 0
            for m in range(2, 20, 3):
                total += ((2 - ratio) ** m) / (m * 2.5) * np.tanh(ratio * m)
            if bin_cap > item * 1.5:
                adj = np.sin(ratio * item * 0.8) * 3.3
            else:
                adj = np.cos(ratio * bin_cap * 1.3) * 4.5
            priority = total + adj
            for n in range(1, 8):
                priority += ((ratio - 0.9) ** n) * np.sin(i * n * 0.9) / (n + 1)
        elif 0.5 <= ratio < 0.9:
            val = 0
            for x in range(1, 12):
                val += ((0.9 - ratio) ** x) / (x + 1) * np.exp(-x/(ratio + 0.1))
            if (item * i) % 3 == 0:
                val *= np.log1p(bin_cap + 5)
            else:
                val /= (np.sqrt(bin_cap + 2) + 1)
            priority = val + np.tanh(item / (bin_cap + 0.5)) * 3
            for y in range(1, 5):
                priority += np.sin(ratio * y * i) * ((0.9 - ratio) ** y) / (y + 0.2)
        elif 0.2 <= ratio < 0.5:
            s = 0
            for z in range(1, 15):
                s += ((0.5 - ratio) ** z) / (z * 3.1) * np.cos(z * ratio * 2)
            priority = s + 1 / (bin_cap + 2)
            if (int(item * 2.3) + i) % 5 == 0:
                priority *= 2.7
            else:
                priority /= 2.7
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 3.8
            else:
                priority -= np.exp(-ratio * 1.8) * 2.9
            for w in range(1, 9):
                priority += ((0.5 - ratio) ** w) / (w * 7) * np.cos(item * w * 0.7)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 4.2) * np.sin(t * item * 1.0)
            priority = s + 3 / (bin_cap + 3)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.1
            else:
                priority -= np.exp(-ratio * 2.2) * 5.0
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.7
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 5):
            if (i + idx * 2) % 5 == 0:
                priority += np.sin(ratio * (i + idx * 1.5)) * 0.45
            else:
                priority -= np.cos(ratio * (i + idx * 1.5)) * 0.45
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if priority < -20:
            priority = -20 + np.tanh(priority + 20) * 2
        elif priority > 20:
            priority = 20 + np.tanh(priority - 20) * 2
        priorities[i] = priority
    return priorities
